1. import * as vscode from 'vscode';
2. import * as path from 'path';
3. import * as os from 'os';
4. import { Logger } from './logger';
5. import { getBackendState } from './backendState';
6. import { ExtensionRpcRouter } from './extension/rpc';
7. import { DisposableStore } from './utilities/disposable';
8. import { CodeReviewSlashHandlers } from './extension/services/slashCommands/CodeReviewSlashHandlers';
9. import { InfoSlashHandlers } from './extension/services/slashCommands/InfoSlashHandlers';
10. import { NotSupportedSlashHandlers } from './extension/services/slashCommands/NotSupportedSlashHandlers';
11. import { CLIPassthroughService } from './extension/services/CLIPassthroughService';
12. import { SessionService } from './extension/services/SessionService';
13. import { resolveImagePaths } from './extension/utils/resolveImagePaths';
14. import * as fs from 'fs';
15. 
16. export class ChatViewProvider implements vscode.WebviewViewProvider, vscode.Disposable {
17. 	public static readonly viewType = 'copilot-cli.chatView';
18. 
19. 	private readonly _disposables = new DisposableStore();
20. 	private _view: vscode.WebviewView | undefined;
21. 	private readonly logger: Logger;
22. 	private readonly extensionUri: vscode.Uri;
23. 	private rpcRouter: ExtensionRpcRouter | undefined;
24. 	private isSessionActive: boolean = false;
25. 	private currentWorkspacePath: string | undefined;
26. 	private lastSentMessage: string | undefined;
27. 	private lastSentTime: number = 0;
28. 	private validateAttachmentsCallback: ((filePaths: string[]) => Promise<{ valid: boolean; error?: string }>) | undefined;
29. 
30. 	// Slash command services
31. 	private codeReviewHandlers?: CodeReviewSlashHandlers;
32. 	private infoHandlers?: InfoSlashHandlers;
33. 	private notSupportedHandlers?: NotSupportedSlashHandlers;
34. 	private cliPassthroughService?: CLIPassthroughService;
35. 
36. 	// Event emitters to replace Set<Function> handlers
37. 	private readonly _onDidReceiveUserMessage = this._reg(new vscode.EventEmitter<{text: string; attachments?: Array<{type: 'file'; path: string; displayName?: string}>}>());
38. 	private readonly _onDidRequestAbort = this._reg(new vscode.EventEmitter<void>());
39. 	private readonly _onDidRequestViewPlan = this._reg(new vscode.EventEmitter<void>());
40. 	private readonly _onDidBecomeReady = this._reg(new vscode.EventEmitter<void>());
41. 	private readonly _onDidRequestSwitchModel = this._reg(new vscode.EventEmitter<string>());
42. 	private readonly _onDidRequestRenameSession = this._reg(new vscode.EventEmitter<string>());
43. 
44. 	// Public events
45. 	readonly onDidReceiveUserMessage = this._onDidReceiveUserMessage.event;
46. 	readonly onDidRequestAbort = this._onDidRequestAbort.event;
47. 	readonly onDidRequestViewPlan = this._onDidRequestViewPlan.event;
48. 	readonly onDidBecomeReady = this._onDidBecomeReady.event;
49. 	readonly onDidRequestSwitchModel = this._onDidRequestSwitchModel.event;
50. 	readonly onDidRequestRenameSession = this._onDidRequestRenameSession.event;
51. 
52. 	constructor(extensionUri: vscode.Uri) {
53. 		this.extensionUri = extensionUri;
54. 		this.logger = Logger.getInstance();
55. 	}
56. 
57. 	private _reg<T extends vscode.Disposable>(disposable: T): T {
58. 		return this._disposables.add(disposable);
59. 	}
60. 
61. 	/**
62. 	 * Called by VS Code when the sidebar view needs to be rendered.
63. 	 * Replaces the old createOrShow() — VS Code owns the view lifecycle.
64. 	 */
65. 	public resolveWebviewView(
66. 		webviewView: vscode.WebviewView,
67. 		_context: vscode.WebviewViewResolveContext,
68. 		_token: vscode.CancellationToken
69. 	): void {
70. 		this._view = webviewView;
71. 
72. 		const webview = webviewView.webview;
73. 		webview.options = {
74. 			enableScripts: true,
75. 			localResourceRoots: [
76. 				this.extensionUri,
77. 				vscode.Uri.file(path.join(os.homedir(), '.copilot')),
78. 				// Full tmpdir needed: pasted images go into random copilot-paste-<uuid> subdirs
79. 				vscode.Uri.file(os.tmpdir()),
80. 				...(vscode.workspace.workspaceFolders ?? []).map(folder => folder.uri)
81. 			]
82. 		};
83. 
84. 		// Listen for visibility changes (replaces onDidChangeViewState)
85. 		this._reg(webviewView.onDidChangeVisibility(() => {
86. 			const visible = webviewView.visible;
87. 			this.logger.debug(`[Visibility] Sidebar ${visible ? 'shown' : 'hidden'}`);
88. 		}));
89. 
90. 		// Handle view disposal (VS Code closes the sidebar)
91. 		webviewView.onDidDispose(() => {
92. 			this.logger.info('[Sidebar] View disposed by VS Code');
93. 			this._view = undefined;
94. 			this.rpcRouter = undefined;
95. 		});
96. 
97. 		// Setup RPC router and handlers
98. 		this._setupRpcHandlers(webview);
99. 
100. 		// Set HTML — webview loads and sends 'ready' which RPC handlers catch
101. 		webview.html = this._getHtmlForWebview(webview);
102. 
103. 		this.logger.info('Sidebar chat view resolved');
104. 	}
105. 
106. 	/**
107. 	 * Focus the sidebar view programmatically.
108. 	 * Replaces panel.reveal() for commands like openChat.
109. 	 */
110. 	public show(): void {
111. 		vscode.commands.executeCommand(`${ChatViewProvider.viewType}.focus`);
112. 	}
113. 
114. 	/**
115. 	 * Check if the view is ready to receive messages.
116. 	 */
117. 	public isViewReady(): boolean {
118. 		return this._view !== undefined && this.rpcRouter !== undefined;
119. 	}
120. 
121. 	/**
122. 	 * Extract RPC handler setup into its own method.
123. 	 * Called once when the view is first resolved.
124. 	 */
125. 	private _setupRpcHandlers(webview: vscode.Webview): void {
126. 		this.rpcRouter = new ExtensionRpcRouter(webview);
127. 
128. 		this._reg(this.rpcRouter.onReady(() => {
129. 			this.logger.info('Webview is ready');
130. 
131. 			const backendState = getBackendState();
132. 			const fullState = backendState.getFullState();
133. 
134. 			this.logger.info(`[Init] Sending ${fullState.messages.length} messages to webview`);
135. 
136. 			this.rpcRouter!.sendInit({
137. 				sessionId: fullState.sessionId,
138. 				sessionActive: fullState.sessionActive,
139. 				messages: fullState.messages as any,
140. 				planModeStatus: fullState.planModeStatus,
141. 				workspacePath: fullState.workspacePath,
142. 				activeFilePath: fullState.activeFilePath,
143. 				currentModel: fullState.currentModel
144. 			});
145. 
146. 			this._onDidBecomeReady.fire();
147. 		}));
148. 
149. 		this._reg(this.rpcRouter.onSendMessage((payload) => {
150. 			// Prevent duplicate sends (same message within 1 second)
151. 			const now = Date.now();
152. 			if (this.lastSentMessage === payload.text &&
153. 			    now - this.lastSentTime < 1000) {
154. 				this.logger.warn(`Ignoring duplicate message send: ${payload.text.substring(0, 50)}...`);
155. 				return;
156. 			}
157. 			this.lastSentMessage = payload.text;
158. 			this.lastSentTime = now;
159. 
160. 			this.logger.info(`User sent message: ${payload.text.substring(0, 100)}...`);
161. 			if (payload.attachments && payload.attachments.length > 0) {
162. 				this.logger.info(`  with ${payload.attachments.length} attachment(s)`);
163. 			}
164. 			this._onDidReceiveUserMessage.fire({
165. 				text: payload.text,
166. 				attachments: payload.attachments
167. 			});
168. 		}));
169. 
170. 		this._reg(this.rpcRouter.onPickFiles(() => {
171. 			this.logger.info('File picker requested from UI');
172. 			this._handleFilePicker();
173. 		}));
174. 
175. 		this._reg(this.rpcRouter.onPasteImage((payload) => {
176. 			this.logger.info(`Pasted image received: ${payload.fileName}`);
177. 			this._handlePastedImage(payload.dataUri, payload.mimeType, payload.fileName);
178. 		}));
179. 
180. 		this._reg(this.rpcRouter.onSaveMermaidImage(async (payload) => {
181. 			this.logger.info('Save mermaid image requested');
182. 			await this._handleSaveMermaidImage(payload.svgContent, payload.source);
183. 		}));
184. 
185. 		this._reg(this.rpcRouter.onAbortMessage(() => {
186. 			this.logger.info('Abort requested from UI');
187. 			this._onDidRequestAbort.fire();
188. 		}));
189. 
190. 		this._reg(this.rpcRouter.onSwitchSession((payload) => {
191. 			this.logger.info(`Switch session requested: ${payload.sessionId}`);
192. 			vscode.commands.executeCommand('copilot-cli-extension.switchSession', payload.sessionId);
193. 		}));
194. 
195. 		this._reg(this.rpcRouter.onNewSession(() => {
196. 			this.logger.info('New session requested from UI');
197. 			vscode.commands.executeCommand('copilot-cli-extension.newSession');
198. 		}));
199. 
200. 		this._reg(this.rpcRouter.onViewPlan(() => {
201. 			this.logger.info('View plan requested from UI');
202. 			this._onDidRequestViewPlan.fire();
203. 		}));
204. 
205. 		this._reg(this.rpcRouter.onViewDiff((payload) => {
206. 			this.logger.info(`View diff requested from UI: ${JSON.stringify(payload)}`);
207. 			vscode.commands.executeCommand('copilot-cli-extension.viewDiff', payload);
208. 		}));
209. 
210. 		this._reg(this.rpcRouter.onTogglePlanMode((payload) => {
211. 			this.logger.info(`Plan mode toggle requested: ${payload.enabled}`);
212. 			vscode.commands.executeCommand('copilot-cli-extension.togglePlanMode', payload.enabled);
213. 		}));
214. 
215. 		this._reg(this.rpcRouter.onAcceptPlan(() => {
216. 			this.logger.info('Accept plan requested from UI');
217. 			vscode.commands.executeCommand('copilot-cli-extension.acceptPlan');
218. 		}));
219. 
220. 		this._reg(this.rpcRouter.onRejectPlan(() => {
221. 			this.logger.info('Reject plan requested from UI');
222. 			vscode.commands.executeCommand('copilot-cli-extension.rejectPlan');
223. 		}));
224. 
225. 		// Initialize slash command services
226. 		// Create sessionService adapter
227. 		const sessionService = {
228. 			getCurrentSession: () => {
229. 				const backendState = getBackendState();
230. 				const sessionId = backendState.getSessionId();
231. 				return sessionId ? { id: sessionId } : null;
232. 			},
233. 			getPlanPath: (sessionId: string) => {
234. 				const sessionStateDir = path.join(os.homedir(), '.copilot', 'session-state');
235. 				return path.join(sessionStateDir, sessionId, 'plan.md');
236. 			}
237. 		};
238. 
239. 		this.codeReviewHandlers = new CodeReviewSlashHandlers(sessionService);
240. 		this.infoHandlers = new InfoSlashHandlers(undefined, getBackendState()); // MCP config will be undefined for now
241. 		this.notSupportedHandlers = new NotSupportedSlashHandlers();
242. 		this.cliPassthroughService = new CLIPassthroughService(vscode);
243. 
244. 		// Handle slash commands from webview
245. 		this._reg(this.rpcRouter.onShowPlanContent(async () => {
246. 			this.logger.info('Show plan content requested from UI');
247. 			const result = await this.codeReviewHandlers!.handleReview();
248. 			if (result.success && result.content) {
249. 				this.rpcRouter!.addAssistantMessage(result.content);
250. 			} else if (result.error) {
251. 				this.rpcRouter!.addAssistantMessage(`Error: ${result.error}`);
252. 			}
253. 		}));
254. 
255. 		this._reg(this.rpcRouter.onOpenDiffView(async (payload) => {
256. 			this.logger.info(`Open diff view requested: ${payload.file1} vs ${payload.file2}`);
257. 			const result = await this.codeReviewHandlers!.handleDiff(payload.file1, payload.file2);
258. 			if (!result.success && result.error) {
259. 				this.rpcRouter!.addAssistantMessage(`Error: ${result.error}`);
260. 			}
261. 		}));
262. 
263. 		this._reg(this.rpcRouter.onShowMcpConfig(async () => {
264. 			this.logger.info('Show MCP config requested from UI');
265. 			const result = await this.infoHandlers!.handleMcp();
266. 			if (result.success && result.content) {
267. 				this.rpcRouter!.addAssistantMessage(result.content);
268. 			} else if (result.error) {
269. 				this.rpcRouter!.addAssistantMessage(`Error: ${result.error}`);
270. 			}
271. 		}));
272. 
273. 		this._reg(this.rpcRouter.onShowUsageMetrics(async () => {
274. 			this.logger.info('Show usage metrics requested from UI');
275. 			const result = await this.infoHandlers!.handleUsage();
276. 			if (result.success && result.content) {
277. 				this.rpcRouter!.addAssistantMessage(result.content);
278. 			} else if (result.error) {
279. 				this.rpcRouter!.addAssistantMessage(`Error: ${result.error}`);
280. 			}
281. 		}));
282. 
283. 		this._reg(this.rpcRouter.onShowHelp(async (payload) => {
284. 			this.logger.info(`Show help requested from UI: ${payload.command || 'all'}`);
285. 			const result = await this.infoHandlers!.handleHelp(payload.command);
286. 			if (result.success && result.content) {
287. 				this.rpcRouter!.addAssistantMessage(result.content);
288. 			} else if (result.error) {
289. 				this.rpcRouter!.addAssistantMessage(`Error: ${result.error}`);
290. 			}
291. 		}));
292. 
293. 		this._reg(this.rpcRouter.onShowNotSupported(async (payload) => {
294. 			this.logger.info(`Not supported command: ${payload.command}`);
295. 			const result = await this.notSupportedHandlers!.handleNotSupported(payload.command);
296. 			if (result.success && result.content) {
297. 				this.rpcRouter!.addAssistantMessage(result.content);
298. 			}
299. 		}));
300. 
301. 		this._reg(this.rpcRouter.onOpenInCLI(async (payload) => {
302. 			this.logger.info(`Open in CLI requested: ${payload.command}`);
303. 			
304. 			// Get current session ID and workspace path
305. 			const backendState = getBackendState();
306. 			const sessionId = backendState.getSessionId();
307. 			const workspacePath = backendState.getWorkspacePath() || this.currentWorkspacePath || null;
308. 
309. 			if (!sessionId) {
310. 				this.rpcRouter!.addAssistantMessage('No active session. Please start a session first.');
311. 				return;
312. 			}
313. 
314. 			const result = this.cliPassthroughService!.openCLI(payload.command, sessionId, workspacePath);
315. 			
316. 			if (result.success && result.instruction) {
317. 				this.rpcRouter!.addAssistantMessage(result.instruction);
318. 			} else if (result.error) {
319. 				this.rpcRouter!.addAssistantMessage(`Error: ${result.error}`);
320. 			}
321. 		}));
322. 
323. 		this._reg(this.rpcRouter.onSwitchModel((payload) => {
324. 			this.logger.info(`Switch model requested: ${payload.model}`);
325. 			this._onDidRequestSwitchModel.fire(payload.model);
326. 		}));
327. 
328. 		this._reg(this.rpcRouter.onRenameSession((payload) => {
329. 			this.logger.info(`Rename session requested: "${payload.name}"`);
330. 			this._onDidRequestRenameSession.fire(payload.name);
331. 		}));
332. 
333. 		this._reg(this.rpcRouter.onOpenFile(async (payload) => {
334. 			this.logger.info(`[OpenFile] ${payload.filePath}`);
335. 			const resolved = path.resolve(payload.filePath);
336. 			const workspaceFolders = vscode.workspace.workspaceFolders?.map(f => f.uri.fsPath) ?? [];
337. 			const sessionStateDir = path.join(os.homedir(), '.copilot', 'session-state');
338. 			const allowed = workspaceFolders.some(ws => resolved.startsWith(ws + path.sep)) ||
339. 				resolved.startsWith(sessionStateDir + path.sep);
340. 			if (!allowed) {
341. 				this.logger.warn(`[OpenFile] Blocked: path outside workspace and session-state`);
342. 				return;
343. 			}
344. 			try {
345. 				const doc = await vscode.workspace.openTextDocument(vscode.Uri.file(resolved));
346. 				await vscode.window.showTextDocument(doc, { preview: true });
347. 			} catch (err: any) {
348. 				this.logger.warn(`[OpenFile] Failed: ${err.message}`);
349. 			}
350. 		}));
351. 
352. 		// Start listening for messages from webview
353. 		this.rpcRouter.listen();
354. 	}
