362. 	public addUserMessage(text: string, attachments?: Array<{displayName: string; webviewUri?: string}>, storeInBackend: boolean = true) {
363. 		if (storeInBackend) {
364. 			const backendState = getBackendState();
365. 			backendState.addMessage({
366. 				role: 'user',
367. 				type: 'user',
368. 				content: text,
369. 				timestamp: Date.now()
370. 			});
371. 		}
372. 		this.rpcRouter?.addUserMessage(text, attachments as any);
373. 	}
