376. 		if (storeInBackend) {
377. 			const backendState = getBackendState();
378. 			backendState.addMessage({
379. 				role: 'assistant',
380. 				type: 'assistant',
381. 				content: text,
382. 				timestamp: Date.now()
383. 			});
384. 		}
385. 
386. 		// Resolve relative image paths in markdown to webview URIs
387. 		const resolvedText = this._resolveAssistantImagePaths(text);
388. 		this.rpcRouter?.addAssistantMessage(resolvedText);
389. 	}
