474. 	private async _handleFilePicker() {
475. 		const options: vscode.OpenDialogOptions = {
476. 			canSelectMany: true,
477. 			openLabel: 'Select Images',
478. 			filters: {
479. 				'Images': ['jpg', 'jpeg', 'png', 'webp', 'gif', 'heic', 'heif']
480. 			}
481. 		};
482. 
483. 		const fileUris = await vscode.window.showOpenDialog(options);
484. 		if (fileUris && fileUris.length > 0) {
485. 			this.logger.info(`[ATTACH] User selected ${fileUris.length} file(s)`);
486. 
487. 			if (this.validateAttachmentsCallback) {
488. 				const filePaths = fileUris.map(uri => uri.fsPath);
489. 				const validationResult = await this.validateAttachmentsCallback(filePaths);
490. 				if (!validationResult.valid) {
491. 					this.logger.warn(`[ATTACH] Validation failed: ${validationResult.error}`);
492. 					vscode.window.showErrorMessage(validationResult.error || 'Invalid attachment');
493. 					return;
494. 				}
495. 			} else {
496. 				this.logger.warn('[ATTACH] No validation callback registered; blocking attachment');
497. 				vscode.window.showErrorMessage('File attachments are not ready yet. Please try again in a moment.');
498. 				return;
499. 			}
500. 
501. 			const attachments = fileUris.map(uri => {
502. 				const webviewUri = this._view?.webview.asWebviewUri(uri);
503. 				return {
504. 					type: 'file' as const,
505. 					path: uri.fsPath,
506. 					displayName: uri.fsPath.split(/[/\\]/).pop() || 'unknown',
507. 					webviewUri: webviewUri?.toString() || ''
508. 				};
509. 			});
510. 
511. 			this.logger.info(`[ATTACH] Sending ${attachments.length} attachments to webview`);
512. 			this.postMessage({
513. 				type: 'filesSelected',
514. 				attachments
515. 			});
516. 		} else {
517. 			this.logger.info('File picker cancelled');
518. 		}
519. 	}
520. 
521. 	private async _handlePastedImage(dataUri: string, _mimeType: string, fileName: string) {
522. 		try {
523. 			// Extract base64 data from data URI
524. 			const base64Data = dataUri.split(',')[1];
525. 			if (!base64Data) {
526. 				this.logger.warn('[PASTE] Invalid data URI — no base64 portion');
527. 				return;
528. 			}
529. 
530. 			const buffer = Buffer.from(base64Data, 'base64');
531. 
532. 			// Write to temp file
533. 			const tempDir = fs.mkdtempSync(path.join(os.tmpdir(), 'copilot-paste-'));
534. 			const tempFilePath = path.join(tempDir, fileName);
535. 			fs.writeFileSync(tempFilePath, buffer);
536. 			this.logger.info(`[PASTE] Wrote temp file: ${tempFilePath} (${buffer.length} bytes)`);
537. 
538. 			// Validate via the same callback as file picker
539. 			if (this.validateAttachmentsCallback) {
540. 				const validationResult = await this.validateAttachmentsCallback([tempFilePath]);
541. 				if (!validationResult.valid) {
542. 					this.logger.warn(`[PASTE] Validation failed: ${validationResult.error}`);
543. 					vscode.window.showErrorMessage(validationResult.error || 'Invalid image');
544. 					// Clean up temp file
545. 					try { fs.unlinkSync(tempFilePath); fs.rmdirSync(tempDir); } catch { /* ignore */ }
546. 					return;
547. 				}
548. 			}
549. 
550. 			// Create webview URI and send back as filesSelected (reuses existing flow)
551. 			const fileUri = vscode.Uri.file(tempFilePath);
552. 			const webviewUri = this._view?.webview.asWebviewUri(fileUri);
553. 			const attachment = {
554. 				type: 'file' as const,
555. 				path: tempFilePath,
556. 				displayName: fileName,
557. 				webviewUri: webviewUri?.toString() || ''
558. 			};
559. 
560. 			this.logger.info(`[PASTE] Sending pasted image attachment to webview`);
561. 			this.postMessage({
562. 				type: 'filesSelected',
563. 				attachments: [attachment]
564. 			});
565. 		} catch (error) {
566. 			this.logger.error('[PASTE] Failed to handle pasted image', error instanceof Error ? error : undefined);
567. 		}
568. 	}
