570. 	private async _handleSaveMermaidImage(svgContent: string, source: string) {
571. 		try {
572. 			const options: vscode.SaveDialogOptions = {
573. 				filters: svgContent
574. 					? { 'SVG Image': ['svg'], 'Mermaid Source': ['mmd'] }
575. 					: { 'Mermaid Source': ['mmd'] }
576. 			};
577. 			const workspaceFolderUri = vscode.workspace.workspaceFolders?.[0]?.uri;
578. 			if (workspaceFolderUri) {
579. 				options.defaultUri = vscode.Uri.joinPath(workspaceFolderUri, 'diagram');
580. 			}
581. 			const uri = await vscode.window.showSaveDialog(options);
582. 			if (!uri) {
583. 				this.logger.info('[Mermaid] Save cancelled');
584. 				return;
585. 			}
586. 
587. 			const isMmd = uri.fsPath.endsWith('.mmd');
588. 			const content = isMmd ? source : svgContent;
589. 			await vscode.workspace.fs.writeFile(uri, Buffer.from(content, 'utf-8'));
590. 			vscode.window.showInformationMessage(`Saved mermaid ${isMmd ? 'source' : 'image'} to ${path.basename(uri.fsPath)}`);
591. 			this.logger.info(`[Mermaid] Saved ${isMmd ? 'source' : 'SVG'} to ${uri.fsPath}`);
592. 		} catch (error) {
593. 			this.logger.error('[Mermaid] Failed to save', error instanceof Error ? error : undefined);
594. 			vscode.window.showErrorMessage('Failed to save mermaid diagram');
595. 		}
596. 	}
597. 
598. 	private _resolveAssistantImagePaths(text: string): string {
599. 		const backendState = getBackendState();
600. 		const sessionId = backendState.getSessionId();
601. 		if (!sessionId || !this._view?.webview) {
602. 			this.logger?.debug(`[ImageResolve] Skipped: sessionId=${!!sessionId} webview=${!!this._view?.webview}`);
603. 			return text;
604. 		}
605. 
606. 		const sessionDir = path.join(os.homedir(), '.copilot', 'session-state', sessionId);
607. 		const webview = this._view.webview;
608. 
609. 		const additionalDirs: string[] = [];
610. 		if (this.currentWorkspacePath) {
611. 			additionalDirs.push(this.currentWorkspacePath);
612. 		}
613. 
614. 		this.logger?.debug(`[ImageResolve] Input: "${text.substring(0, 100)}" sessionDir=${sessionDir} additionalDirs=${JSON.stringify(additionalDirs)}`);
615. 
616. 		const result = resolveImagePaths(text, sessionDir, (absolutePath: string) => {
617. 			const exists = fs.existsSync(absolutePath);
618. 			this.logger?.debug(`[ImageResolve] Check: ${absolutePath} exists=${exists}`);
619. 			if (!exists) {
620. 				return null;
621. 			}
622. 			const fileUri = vscode.Uri.file(absolutePath);
623. 			const uri = webview.asWebviewUri(fileUri).toString();
624. 			this.logger?.debug(`[ImageResolve] Resolved: ${uri}`);
625. 			return uri;
626. 		}, additionalDirs);
627. 
628. 		if (result !== text) {
629. 			this.logger?.info(`[ImageResolve] Resolved image paths in message`);
630. 			this.logger?.debug(`[ImageResolve] Output: "${result.substring(0, 200)}"`);
631. 		}
632. 
633. 		return result;
634. 	}
