636. 	public setValidateAttachmentsCallback(callback: (filePaths: string[]) => Promise<{ valid: boolean; error?: string }>) {
637. 		this.validateAttachmentsCallback = callback;
638. 		this.logger?.info('Attachment validation callback registered');
639. 	}
