641. 	/**
642. 	 * Force refresh the webview content.
643. 	 * For sidebar views, we can't dispose/recreate — just reset the HTML.
644. 	 */
645. 	public forceRecreate() {
646. 		if (this._view) {
647. 			this._view.webview.html = this._getHtmlForWebview(this._view.webview);
648. 			this.resetPlanMode();
649. 		}
650. 	}
