658. 	private _getHtmlForWebview(webview: vscode.Webview) {
659. 		const nonce = getNonce();
660. 
661. 		const styleUri = webview.asWebviewUri(
662. 			vscode.Uri.joinPath(this.extensionUri, 'dist', 'webview', 'styles.css')
663. 		);
664. 		const scriptUri = webview.asWebviewUri(
665. 			vscode.Uri.joinPath(this.extensionUri, 'dist', 'webview', 'main.js')
666. 		);
667. 
668. 		return `<!DOCTYPE html>
669. <html lang="en">
670. <head>
671. 	<meta charset="UTF-8">
672. 	<meta name="viewport" content="width=device-width, initial-scale=1.0">
673. 	<meta http-equiv="Content-Security-Policy" content="default-src 'none'; style-src ${webview.cspSource} 'unsafe-inline'; script-src 'nonce-${nonce}' ${webview.cspSource} https://cdn.jsdelivr.net; img-src ${webview.cspSource} data:; font-src ${webview.cspSource} data:;">
674. 	<title>Copilot CLI Chat</title>
675. 	<script nonce="${nonce}" src="https://cdn.jsdelivr.net/npm/marked@11.1.1/marked.min.js"></script>
676. 	<link rel="stylesheet" href="${styleUri}">
677. </head>
678. <body>
679. 	<!-- Component Mount Points - Components render themselves here -->
680. 	<div id="session-toolbar-mount"></div>
681. 
682. 	<main role="main">
683. 		<div id="messages-mount"></div>
684. 		<div id="acceptance-mount"></div>
685. 		<div id="input-mount"></div>
686. 	</main>
687. 
688. 	<script type="module" nonce="${nonce}" src="${scriptUri}"></script>
689. </body>
690. </html>`;
691. 	}
692. 
693. }
694. 
695. function getNonce() {
696. 	let text = '';
697. 	const possible = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
698. 	for (let i = 0; i < 32; i++) {
699. 		text += possible.charAt(Math.floor(Math.random() * possible.length));
700. 	}
701. 	return text;
702. }
